public PeriodFormatter toFormatter() {
    List<Object> elements;

    elements = Arrays.asList(
      this.yPrefix != null ? new Literal(this.yPrefix) : null,
      this.years == 0 ? null : YEARS_FIELD,

      this.mPrefix != null ? new Literal(this.mPrefix) : null,
      this.months == 0 ? null : MONTHS_FIELD,

      this.wPrefix != null ? new Literal(this.wPrefix) : null,
      this.weeks == 0 ? null : WEEKS_FIELD,

      this.dPrefix != null ? new Literal(this.dPrefix) : null,
      this.days == 0 ? null : DAYS_FIELD,

      this.separator != null ? new Separator(this.separator) : null,

      this.hPrefix != null ? new Literal(this.hPrefix) : null,
      this.hours == 0 ? null : HOURS_FIELD,

      this.miPrefix != null ? new Literal(this.miPrefix) : null,
      this.minutes == 0 ? null : MINUTES_FIELD,

      this.sPrefix != null ? new Literal(this.sPrefix) : null,
      this.seconds == 0 ? null : SECONDS_FIELD,

      this.msPrefix != null ? new Literal(this.msPrefix) : null,
      this.millis == 0 ? null : MILLIS_FIELD
    );

    if (!this.omitEmptyFields) {
        elements.replaceAll(e -> e == null ? EMPTY_FIELD : e);
    }

    return Formats.periodFormatter().withElements(elements).create();
}

